import { useState } from 'react';

// Controlled input — state and DOM are always in sync
function NameInput() {
  const [name, setName] = useState('');

  return (
    <div>
      <input
        value={name}                              // React controls the value
        onChange={e => setName(e.target.value)}  // fires on every keystroke
        placeholder="Enter your name"
      />
      <p>Hello, {name}!</p>  {/* updates live */}
    </div>
  );
}

import { useState } from 'react';

function SignUpForm() {
  const [form, setForm] = useState({
    username: '',
    age: '',
    agreed: false,
    plan: 'free',
    country: 'US',
  });

  const handleChange = e => {
    const { name, value, type, checked } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value,
    }));
  };

  return (
    <form>
      <input name="username" value={form.username} onChange={handleChange} />

      {/* type="number" — value is still a string; parse when you need a number */}
      <input name="age" type="number" value={form.age} onChange={handleChange} />

      {/* Checkbox — use checked, not value */}
      <label>
        <input
          name="agreed"
          type="checkbox"
          checked={form.agreed}
          onChange={handleChange}
        />
        I agree
      </label>

      <select name="country" value={form.country} onChange={handleChange}>
        <option value="US">United States</option>
        <option value="GB">United Kingdom</option>
        <option value="CA">Canada</option>
      </select>
    </form>
  );
}

import { useState } from 'react';

function ValidatedInput({ label, validate }) {
  const [value, setValue] = useState('');
  const [touched, setTouched] = useState(false);
  const error = touched ? validate(value) : null;

  return (
    <div>
      <label>{label}</label>
      <input
        value={value}
        onChange={e => setValue(e.target.value)}
        onFocus={() => {
          // Optional: select all text when user focuses
          // e.target.select();
        }}
        onBlur={() => setTouched(true)}  // mark as touched when leaving
        aria-invalid={!!error}
        style={{ borderColor: error ? 'red' : undefined }}
      />
      {error && <span role="alert" style={{ color: 'red', fontSize: 12 }}>{error}</span>}
    </div>
  );
}

// Usage:
<ValidatedInput
  label="Email"
  validate={v => (/^[^@]+@[^@]+\.[^@]+$/.test(v) ? null : 'Invalid email address')}
/>

// Detect when focus enters/leaves the entire form section
function FormSection({ children }) {
  const [hasFocus, setHasFocus] = useState(false);

  return (
    <fieldset
      onFocus={() => setHasFocus(true)}
      onBlur={e => {
        // relatedTarget is the element receiving focus next
        // If it's inside this fieldset, we're still focused within the section
        if (!e.currentTarget.contains(e.relatedTarget)) {
          setHasFocus(false);
        }
      }}
      style={{ border: hasFocus ? '2px solid #3b82f6' : '2px solid #d1d5db' }}
    >
      {children}
    </fieldset>
  );
}
// The relatedTarget trick: if focus moves to an element outside currentTarget,
// it means the user has truly left this section — otherwise it moved between
// inputs inside the section and we should keep hasFocus=true.

import { useState } from 'react';

function LoginForm() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async e => {
    e.preventDefault(); // REQUIRED — prevents page reload

    setLoading(true);
    setError(null);
    try {
      await login({ email, password });
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>   {/* attach to <form>, not <button> */}
      <input
        type="email"
        value={email}
        onChange={e => setEmail(e.target.value)}
        required
      />
      <input
        type="password"
        value={password}
        onChange={e => setPassword(e.target.value)}
        required
        minLength={8}
      />
      {error && <p role="alert" style={{ color: 'red' }}>{error}</p>}
      <button type="submit" disabled={loading}>
        {loading ? 'Logging in…' : 'Log in'}
      </button>
    </form>
  );
}

