// No useState needed for read-only-on-submit forms.
// FormData automatically picks up all named inputs including selects and checkboxes.

import { useState } from 'react';

function FileUpload() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);

  const handleChange = e => {
    const selected = e.target.files[0];
    if (!selected) return;
    setFile(selected);
    // Generate preview URL for images
    if (selected.type.startsWith('image/')) {
      setPreview(URL.createObjectURL(selected));
    }
  };

  return (
    <div>
      <input type="file" accept="image/*" onChange={handleChange} />
      {preview && (
        <img src={preview} alt="Preview" style={{ maxWidth: 200 }} />
      )}
      {file && <p>{file.name} ({Math.round(file.size / 1024)} KB)</p>}
    </div>
  );
}

import { useState } from 'react';

const SKILLS = ['React', 'TypeScript', 'Node.js', 'CSS', 'SQL'];

function SkillPicker() {
  const [selected, setSelected] = useState([]);

  const handleChange = e => {
    const options = Array.from(e.target.selectedOptions);
    setSelected(options.map(opt => opt.value));
  };

  return (
    <div>
      <select multiple value={selected} onChange={handleChange} size={5}>
        {SKILLS.map(skill => (
          <option key={skill} value={skill}>{skill}</option>
        ))}
      </select>
      <p>Selected: {selected.join(', ') || 'none'}</p>
    </div>
  );
}

import { render, screen, fireEvent } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

test('typing updates the input value', async () => {
  render(<NameInput />);
  const input = screen.getByRole('textbox');

  await userEvent.type(input, 'Alice');
  expect(input).toHaveValue('Alice');
});

test('blur shows validation error', async () => {
  render(<ValidatedInput label="Email" validate={v =>
    /^[^@]+@[^@]+\.[^@]+$/.test(v) ? null : 'Invalid email'
  } />);

  const input = screen.getByRole('textbox');
  await userEvent.type(input, 'not-an-email');
  // Error should not be visible yet
  expect(screen.queryByRole('alert')).not.toBeInTheDocument();
  // Blur
  await userEvent.tab();
  expect(screen.getByRole('alert')).toHaveTextContent('Invalid email');
});

test('submit calls handler with form data', async () => {
  const onSubmit = jest.fn();
  render(<LoginForm onSubmit={onSubmit} />);

  await userEvent.type(screen.getByLabelText(/email/i), 'a@b.com');
  await userEvent.type(screen.getByLabelText(/password/i), 'secret123');
  await userEvent.click(screen.getByRole('button', { name: /log in/i }));

  expect(onSubmit).toHaveBeenCalledTimes(1);
});

test('checkbox change updates checked state', async () => {
  render(<SignUpForm />);
  const checkbox = screen.getByRole('checkbox', { name: /agree/i });
  expect(checkbox).not.toBeChecked();
  await userEvent.click(checkbox);
  expect(checkbox).toBeChecked();
});

