import { useState, useEffect } from 'react';

function SearchInput({ onSearch }) {
  const [query, setQuery] = useState('');

  // Debounce: only call onSearch 400ms after the user stops typing
  useEffect(() => {
    const timer = setTimeout(() => {
      if (query.trim()) onSearch(query);
    }, 400);
    return () => clearTimeout(timer); // cancel if query changes before 400ms
  }, [query, onSearch]);

  return (
    <input
      value={query}
      onChange={e => setQuery(e.target.value)} // still updates state on every keystroke
      placeholder="Search…"
    />
  );
}
// The input remains responsive (state updates every keystroke).
// The search only runs after a 400ms pause in typing.
// The cleanup cancels any pending timer when the component unmounts or query changes.

import { useState } from 'react';

const STEPS = ['Personal', 'Account', 'Confirm'];

function MultiStepForm() {
  const [step, setStep] = useState(0);
  const [data, setData] = useState({ name: '', email: '', password: '' });
  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});

  const handleChange = e => {
    const { name, value } = e.target;
    setData(prev => ({ ...prev, [name]: value }));
  };

  const handleBlur = e => {
    setTouched(prev => ({ ...prev, [e.target.name]: true }));
  };

  const validate = () => {
    const errs = {};
    if (!data.name) errs.name = 'Name is required';
    if (!data.email.includes('@')) errs.email = 'Invalid email';
    if (data.password.length < 8) errs.password = 'At least 8 characters';
    return errs;
  };

  const handleNext = e => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) {
      setErrors(errs);
      // Mark all fields as touched so errors appear
      setTouched({ name: true, email: true, password: true });
      return;
    }
    setStep(s => s + 1);
  };

  const handleSubmit = e => {
    e.preventDefault();
    console.log('Submitting:', data);
  };

  const renderStep = () => {
    if (step === 0) return (
      <div>
        <input name="name" value={data.name} onChange={handleChange} onBlur={handleBlur} placeholder="Full name" />
        {touched.name && errors.name && <span>{errors.name}</span>}
      </div>
    );
    if (step === 1) return (
      <div>
        <input name="email" value={data.email} onChange={handleChange} onBlur={handleBlur} placeholder="Email" />
        {touched.email && errors.email && <span>{errors.email}</span>}
        <input name="password" type="password" value={data.password} onChange={handleChange} onBlur={handleBlur} placeholder="Password" />
        {touched.password && errors.password && <span>{errors.password}</span>}
      </div>
    );
    return <p>Confirm: {data.name} / {data.email}</p>;
  };

  return (
    <form onSubmit={step < STEPS.length - 1 ? handleNext : handleSubmit}>
      <h3>Step {step + 1} of {STEPS.length}: {STEPS[step]}</h3>
      {renderStep()}
      <button type="submit">{step < STEPS.length - 1 ? 'Next' : 'Submit'}</button>
    </form>
  );
}
